-- DVAS P0 seed data
-- 初始化菜单、权限、角色、本地操作员、质量指标模板和系统参数。

BEGIN;
SET search_path TO dvas;
-- nav_menu

-- permission

-- users and roles

-- local_operator gets all P0 permissions, excluding P1-only actions by default

SELECT 'RP_LOCAL_' || permission_id, 'ROLE_LOCAL_OPERATOR', permission_id
FROM permission
WHERE p1_only = false
ON CONFLICT (role_id, permission_id) DO NOTHING;

-- quality_metric_template
UPDATE quality_metric_template
SET status='INACTIVE', updated_at=now()
WHERE metric_id IN (
  'QM_COMPLETENESS','QM_ACCURACY','QM_TIMELINESS','QM_CONSISTENCY','QM_UNIQUENESS',
  'QM_COMPLETENESS_MISSING','QM_COMPLETENESS_COVERAGE','QM_ACCURACY_OUTLIER','QM_ACCURACY_VALIDATION'
);
ON CONFLICT (metric_id) DO UPDATE SET metric_code=EXCLUDED.metric_code,parent_metric_code=EXCLUDED.parent_metric_code,metric_name=EXCLUDED.metric_name,metric_level=EXCLUDED.metric_level,default_weight=EXCLUDED.default_weight,score_rule_json=EXCLUDED.score_rule_json,status=EXCLUDED.status,updated_at=now();

-- system_parameter and parameter_version

COMMIT;
